 前言： # Links: A. Catch the Coin Codeforces: \(800\) Clist: \(784\) Tags: 模拟 时间复杂度: \(O(1)\) 题意： # 给你一个硬币的坐标 \((x, y)\) ，你初始位置在 \((0, 0)\) ，对于每一时刻均可以向满足 \(|x&#39;-x| &#43; |y&#39;-y| \le 2\) 的点 \((x&#39;, y&#39;)\) 移动，硬币在你移动后坐标变为 \((x, y - 1)\) ，问你是否有一时刻可以接到硬币
思路： # 观察可以发现，只有当 \(y \geq -1\) 时才满足条件
代码： # #include &lt;bits/stdc++.h&gt; using namespace std; void code(/* Copyright by Urtusea */) { int x, y; cin &gt;&gt; x &gt;&gt; y; // 只需判断 y &gt;= -1 即可 if (y &gt;= -1) cout &lt;&lt; &#34;YES\n&#34;; else cout &lt;&lt; &#34;NO\n&#34;; } int main(int argc, char *argv[], char *envp[]) { cin.tie(nullptr)-&gt;sync_with_stdio(false); #ifdef Urtusea freopen(&#34;main.in&#34;, &#34;r&#34;, stdin ); freopen(&#34;main.out&#34;, &#34;w&#34;, stdout); #endif for (int i = 1, n = (cin &gt;&gt; n, n); i &lt;= n; i++) { code(); } return 0; }

 前言： # Links: D. Smithing Skill Codeforces: \(1900\) Clist: \(1914\) Tags: DP，贪心 时间复杂度: \(O(N)\) 题意： # 给你两个大小为 \(n\) 的序列 \(a, b\) ，和一个大小为 \(m\) 的序列 \(c\) ，对于每一个 \(c_i\) 你都可以花费 \(a_j\) 并获得 \(b_j\) 的返还，最终获得 \(2\) 点贡献，可以进行多次这样的操作，直到无法进行为止，问你最大能获得的贡献为多少
思路： # 对于每个相同的 \(a_i, a_j\) 只需要考虑对应的 \(max(b_i, b_j)\) 即可，很简单的贪心，然后会发现，小范围以内的数我们可以直接通过 DP 将答案递推出来，而超过这个范围的我们也只需要贪心的降到小范围里面加上其值即可
代码： # #include &lt;bits/stdc++.h&gt; using namespace std; void code(/* Copyright by Urtusea */) { int n, m; cin &gt;&gt; n &gt;&gt; m; vector&lt;int&gt; a(n + 1), b(n + 1), c(m + 1); for (int i = 1; i &lt;= n; i++) cin &gt;&gt; a[i]; for (int i = 1; i &lt;= n; i++) cin &gt;&gt; b[i]; for (int i = 1; i &lt;= m; i++) cin &gt;&gt; c[i]; const int N = 1000000, INF = 1000000000; // 预处理 vector&lt;int&gt; p(N + 1, INF), f(N + 1), g(N + 1); for (int i = 1; i &lt;= n; i++) p[a[i]] = min(p[a[i]], a[i] - b[i]); iota(f.begin(), f.end(), 0); // DP 预处理 [1, 1e6] 的答案 for (int i = 1; i &lt;= N; i++) { if (p[f[i - 1]] &lt;= p[f[i]]) f[i] = f[i - 1]; if (p[f[i]] == INF) continue; int tmp = (i - f[i]) / p[f[i]] + 1; g[i] = tmp + g[i - tmp * p[f[i]]]; } // 贪心求解 long long ans = 0; for (int i = 1; i &lt;= m; i++) { int mId = min(c[i], N); if (p[f[mId]] == INF) continue; int tmp = (c[i] - f[mId]) / p[f[mId]] + 1; ans += tmp + g[c[i] - tmp * p[f[mId]]]; } cout &lt;&lt; ans * 2 &lt;&lt; &#39;\n&#39;; } int main(int argc, char *argv[], char *envp[]) { cin.tie(nullptr)-&gt;sync_with_stdio(false); #ifdef Urtusea freopen(&#34;main.in&#34;, &#34;r&#34;, stdin ); freopen(&#34;main.out&#34;, &#34;w&#34;, stdout); #endif // for (int i = 1, n = (cin &gt;&gt; n, n); i &lt;= n; i++) { code(); } return 0; }
